sql:
SELECT clothing_type_name, measurement_unit
FROM clothing_types
ORDER BY measurement_unit DESC;

external_knowledge:
- 'maestros' are master craftsmen or artists, here referring to users with the 'designer' role;
- 'woven the most fabrics' metaphorically refers to having created the most size charts;
- 'sacred key of creation' symbolizes the 'CREATE' permission;
- 'top five' refers to the limit of five results where the rank is <= 5.

sql:
SELECT brand_id, brand_name, COUNT(*) AS brand_count
FROM brands
GROUP BY brand_id, brand_name;

SELECT measurement_unit, COUNT(clothing_type_id) AS num_clothing_types
FROM clothing_types
GROUP BY measurement_unit;
